// ═══════════════════════════════════════════════════════
// Step 8: Parse LLM Result + Benchmark-Abgleich
// Generisch: Verwendet config fuer Firmennamen
// ═══════════════════════════════════════════════════════
const llmResp = $input.item.json;
const fact = $('06 - Parse RAG + Build LLM Request').item.json;
const config = fact.config;

let answer = (llmResp.choices?.[0]?.message?.content || '')
  .replace(/<think>[\s\S]*?<\/think>/g, '')
  .trim();

// Bewertung extrahieren (letzter Satz oder Zeile mit 'besser'/'gleichwertig')
let bewertung = 'nicht ermittelt';
const bewertungMatch = answer.match(new RegExp(
  `(${config.ownCompanyShort}\\s+besser|${config.competitorShort}\\s+besser|gleichwertig|nicht vergleichbar)`,
  'i'
));
if (bewertungMatch) {
  bewertung = bewertungMatch[1];
}

return {
  id: fact.id,
  kategorie: fact.kategorie,
  aspekt: fact.aspekt,
  own_data: fact.own_data,
  benchmark_competitor: fact.benchmark_competitor,
  vergleich_aus_rag: answer,
  bewertung: bewertung,
  ragChunkCount: fact.ragChunkCount,
  ragDistances: fact.ragDistances,
  tokens: llmResp.usage?.total_tokens || 0,
  config: config
};
